// // This module implements a 16-bit shift register with parallel load capability.
// It has inputs for 16-bit data, clock, load, and shift signals.
// When the load signal is high, the data should be shifted right by one bit on each clock cycle.
// When the shift signal is high, the data should be loaded into the shift register.
// If both load and shift are low, the register should hold its value.
// The output of the shift register should be available as a 16-bit output.
module shift_register (
    input wire [15:0] data_in,
    input wire load,
    input wire shift,
    input wire clk,
    output reg [15:0] data_out
);

    always @(posedge clk) begin
        if (load) begin
            data_out <= data_in; // Load data
        end else if (shift) begin
            data_out <= {1'b0, data_out[15:1]}; // Shift right
        end
        // If both load and shift are low, hold the value
    end
endmodule

